#include <vector>
#include <algorithm>

void adaptive_sort(std::vector<int>& arr) {
    if (arr.size() < 2) return;

    auto it = std::is_sorted_until(arr.begin(), arr.end());
    if (it == arr.end()) return;

    // If only a few elements are unsorted at the end, use insertion sort
    if (arr.end() - it < 24) {
        for (; it != arr.end(); ++it) {
            int key = *it;
            auto j = it;
            while (j > arr.begin() && *(j - 1) > key) {
                *j = *(j - 1);
                --j;
            }
            *j = key;
        }
    } else if (arr[0] >= arr[1] && std::is_sorted(arr.rbegin(), arr.rend())) {
        std::reverse(arr.begin(), arr.end());
    } else {
        std::sort(arr.begin(), arr.end());
    }
}

